answer.referenceSolution:
#include <iostream>

class Employee {
protected:
    long long base_pay_;
public:
    explicit Employee(long long base_pay) : base_pay_(base_pay) {}
};
class Developer : public Employee {
public:
    using Employee::Employee;
    long long total_pay(long long bonus) const { return base_pay_ + bonus; }
};

int main() {
    long long base{}, bonus{};
    if (!(std::cin >> base >> bonus)) return 1;
    Developer developer(base);
    std::cout << developer.total_pay(bonus) << '\n';
}
